import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void classic() {
        assertTrue(new Solution().isAnagram("listen", "silent"));
    }

    @Test
    void notAnagram() {
        assertFalse(new Solution().isAnagram("hello", "world"));
    }

    @Test
    void differentLengths() {
        assertFalse(new Solution().isAnagram("abc", "abcd"));
    }

    @Test
    void bothEmpty() {
        assertTrue(new Solution().isAnagram("", ""));
    }

    @Test
    void sameChars() {
        assertTrue(new Solution().isAnagram("a", "a"));
    }

    @Test
    void differentCounts() {
        // both have a, b, c — but counts differ: "aabc" has a×2, "abbc" has b×2
        assertFalse(new Solution().isAnagram("aabc", "abbc"));
    }
}
